mapper.select:
select a.ts_code,b.name,b.industry_name_l1,b.industry_name_l2,b.industry_name_l3 ,a.open,
b.area,a.pct_chg,a.close,a.pre_close,a.high,a.low,a.pe_ttm,a.pb,a.ps_ttm,a.volume_ratio,
a.turnover_rate,a.amount,b.market,a.total_mv,a.trade_date,c.ratio,a.total_mv/a.pb as asset,
a.total_mv/a.ps_ttm as sales,a.total_mv/a.pe_ttm as profit
from common_daily.`${tradeDate}` as a left join stock_list.industry_member as b on a.ts_code=b.ts_code
left join hsgt.`20260331` as c on b.ts_code = c.ts_code


        index_code_l1


        index_code_l2


        index_code_l3


        area

    =#{industryCode}

        order by total_mv desc;


        order by industry_name_l1, industry_name_l2, industry_name_l3, total_mv desc;


        order by asset desc;


        order by pct_chg desc;


        order by ratio desc;


        order by sales desc;


        order by profit desc;

select a.ts_code,b.name,b.area,a.pct_chg,b.industry_name_l1 ,b.industry_name_l2
,b.industry_name_l3,c.main_business,b.market,a.total_mv,a.pb,a.trade_date,a.total_mv/a.pb as asset
from common_daily.`${tradeDate}` as a
left join stock_list.industry_member as b
on a.ts_code=b.ts_code
left join finance.fina_main as c
on b.ts_code = c.ts_code


        index_code_l1


        index_code_l2


        index_code_l3


        area

    =#{industryCode}

        order by total_mv desc;


        order by industry_name_l1, industry_name_l2, industry_name_l3, total_mv desc;


        order by asset desc;


        order by pct_chg desc;

select a.ts_code, a.trade_date, b.name, b.market, a.pb, a.total_mv, a.pct_chg, c.province, c.city, c.introduction, industry_name_l1, industry_name_l2, industry_name_l3, a.total_mv/a.pb as asset from common_daily.`${tradeDate}` as a left join stock_list.industry_member as b on a.ts_code = b.ts_code left join stock_list.stock_company as c on b.ts_code = c.ts_code
index_code_l1
index_code_l2
index_code_l3
area
= #{industryCode}
order by total_mv desc;
order by industry_name_l1, industry_name_l2, industry_name_l3, total_mv desc;
order by asset desc;
order by pct_chg desc;

select a.ts_code, a.trade_date, b.name, b.market, a.pb, a.total_mv, a.pct_chg, c.province, c.city, c.main_business , c.business_scope , industry_name_l1, industry_name_l2, industry_name_l3, a.total_mv/a.pb as asset from common_daily.`${tradeDate}` as a left join stock_list.industry_member as b on a.ts_code = b.ts_code left join stock_list.stock_company as c on b.ts_code = c.ts_code
index_code_l1
index_code_l2
index_code_l3
area
= #{industryCode}
order by total_mv desc;
order by industry_name_l1, industry_name_l2, industry_name_l3, total_mv desc;
order by asset desc;
order by pct_chg desc;
